app.post('/authorize', (req, res) => {
  const { response_type, client_id, redirect_uri, state, username, password } = req.body;
  const validation = validateAuthorizeRequest({ response_type, client_id, redirect_uri });

  if (validation.error) {
    if (redirect_uri && client_id && clients.has(client_id)) {
      const client = clients.get(client_id);
      if (client.redirect_uris.includes(redirect_uri)) {
        return sendOAuthErrorRedirect(res, redirect_uri, validation.error, state);
      }
    }
    return res.status(400).json(validation);
  }

  const user = users.get(username);
  if (!user || user.password !== password) {
    return sendOAuthErrorRedirect(res, redirect_uri, 'access_denied', state);
  }

  const code = randomString(24);
  authorizationCodes.set(code, {
    code,
    client_id,
    redirect_uri,
    user_id: user.id,
    username: user.username,
    created_at: Date.now(),
    expires_at: Date.now() + 5 * 60 * 1000,
    used: false
  });

  const redirectUrl = new URL(redirect_uri);
  redirectUrl.searchParams.set('code', code);
  if (state) redirectUrl.searchParams.set('state', state);

  return res.redirect(redirectUrl.toString());
});

app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;

  if (grant_type !== 'authorization_code') {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: 'grant_type must be authorization_code'
    });
  }

  if (!client_id || !client_secret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'client authentication failed'
    });
  }

  const client = clients.get(client_id);
  if (!client || client.client_secret !== client_secret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'client authentication failed'
    });
  }

  const authCode = authorizationCodes.get(code);
  if (!authCode) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'authorization code is invalid'
    });
  }

  if (authCode.used) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'authorization code has already been used'
    });
  }

  if (Date.now() > authCode.expires_at) {
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'authorization code has expired'
    });
  }

  if (authCode.client_id !== client_id) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'authorization code was not issued to this client'
    });
  }

  if (authCode.redirect_uri !== redirect_uri) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'redirect_uri does not match'
    });
  }

  authCode.used = true;

  const accessToken = randomString(32);
  accessTokens.set(accessToken, {
    access_token: accessToken,
    token_type: 'Bearer',
    client_id,
    user_id: authCode.user_id,
    username: authCode.username,
    created_at: Date.now(),
    expires_at: Date.now() + 60 * 60 * 1000
  });

  authorizationCodes.delete(code);

  return res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600
  });
});

